const update = $json;
const text = update.message?.text || '';
const parts = text.trim().split(/\s+/);
const command = parts[0] || '';

// Парсим либо команду /new_project, либо полное ТЗ
let game = 'Minecraft';
let template = 'Crafty';
let targetCount = 50;

if (command === '/new_project') {
  const args = parts.slice(1);
  game = args[0] || 'Minecraft';
  template = args[1] || 'Crafty';
  targetCount = args[3] ? Number(args[3]) : 50;
} else if (text.includes('Сегмент:') || text.includes('Minecraft')) {
  // Парсим ТЗ
  game = 'Minecraft';
  template = 'Crafty';

  // Извлекаем секции из ТЗ
  const sections = [];
  if (text.includes('Mods')) sections.push('mods');
  if (text.includes('Maps')) sections.push('maps');
  if (text.includes('Skins')) sections.push('skins');
  if (text.includes('Addons')) sections.push('addons');
  if (text.includes('Shaders')) sections.push('shaders');
  if (text.includes('Items')) sections.push('items');
}

return [{
  json: {
    chat_id: update.message.chat.id,
    message_id: update.message.message_id,
    raw_text: text,
    command,
    game,
    template,
    target_count: targetCount,
    created_at: new Date().toISOString()
  }
}];

const project = $json;
const tasks = [];
const sections = project.sections || [];

for (const section of sections) {
  tasks.push({
    project_game: project.game,
    project_template: project.template,
    section_key: section.key,
    section_name: section.name,
    target_items: section.min_items || 50,
    needs_file: section.needs_file || false,
    file_formats: section.file_formats || [],
    image_size: section.image_size || '640x480',
    image_orientation: section.image_orientation || 'landscape',
    base_output_dir: project.base_output_dir,
    text_rules: project.text_rules || {},
    chat_id: project.chat_id
  });
}

return tasks.map(t => ({ json: t }));

// Подготовка промпта для Manus AI
const task = $json;

const categoryMap = {
  'mods': 'https://mcpedl.com/category/mods/',
  'addons': 'https://mcpedl.com/category/mods/addons/',
  'maps': 'https://mcpedl.com/category/maps/',
  'skins': 'https://mcpedl.com/skins/',
  'shaders': 'https://mcpedl.com/resolution/shaders/',
  'items': 'https://mcpedl.com/category/mods/'
};

const sectionKey = (task.section_key || 'mods').toLowerCase();
const targetUrl = categoryMap[sectionKey] || categoryMap['mods'];
const targetItems = task.target_items || 50;
const needsFiles = task.needs_file || false;
const fileFormats = task.file_formats || [];

const prompt = `## ЗАДАЧА
Собери список из ${targetItems} элементов (${task.section_name}) с сайта mcpedl.com

## URL ДЛЯ ПАРСИНГА
${targetUrl}

## ЧТО НУЖНО СОБРАТЬ
Для КАЖДОГО элемента:

1. **title** — название (как на сайте)
2. **page_url** — полный URL страницы (https://mcpedl.com/...)
3. **image_url** — URL превью-картинки (обычно media.forgecdn.net или r2.mcpedl.com)
4. **description** — краткое описание
${needsFiles ? `5. **download_url** — ПРЯМАЯ ссылка на скачивание файла (${fileFormats.join(' или ')})
6. **file_extension** — расширение файла` : ''}

## АЛГОРИТМ
1. Открой ${targetUrl}
2. Собери все элементы
${needsFiles ? '3. Для КАЖДОГО зайди на страницу и найди прямую ссылку на скачивание' : ''}
4. Если мало — перейди на page/2/, page/3/ и т.д.
5. Собери минимум ${targetItems} элементов

## ФОРМАТ ОТВЕТА (только JSON, без markdown)
{
  "section": "${sectionKey}",
  "items": [
    {
      "title": "Название",
      "page_url": "https://mcpedl.com/example/",
      "image_url": "https://media.forgecdn.net/...",
      "description": "Описание"${needsFiles ? `,
      "download_url": "https://...",
      "file_extension": "${fileFormats[0] || '.mcaddon'}"` : ''}
    }
  ],
  "total_count": ${targetItems}
}

## ВАЖНО
- Работай АВТОНОМНО
- Верни ТОЛЬКО JSON
- ВСЕ URL полные (https://)
- Пропускай элементы без картинки${needsFiles ? ' или без файла' : ''}`;

return [{
  json: {
    task: task,
    manus_prompt: prompt,
    target_url: targetUrl,
    needs_files: needsFiles
  }
}];

// Парсим JSON от Manus (скачанный файл)
const response = $json;
const prevData = $('Prepare Manus Prompt1').first().json;
const taskInfo = prevData.task || {};
const needsFiles = prevData.needs_files || false;

let items = [];

// response может быть массивом или объектом
if (Array.isArray(response)) {
  items = response[0]?.items || [];
} else {
  items = response.items || [];
}

const formattedItems = items.map((item, index) => ({
  id: `${taskInfo.section_key || 'item'}_${Date.now()}_${index}`,
  section: taskInfo.section_key || 'mods',
  section_name: taskInfo.section_name || 'Mods',
  category: 'general',
  raw_title: item.title || `Item ${index + 1}`,
  page_url: item.page_url || '',
  image_url: item.image_url || '',
  download_url: item.download_url || null,
  file_extension: item.file_extension || null,
  raw_description: item.description || '',
  needs_file: needsFiles,
  image_size: taskInfo.image_size || '640x480',
  source: 'mcpedl.com'
}));

return [{
  json: {
    task: taskInfo,
    items: formattedItems,
    total_count: formattedItems.length,
    parse_error: null,
    needs_files: needsFiles
  }
}];

// Разбиваем items
const data = $json;
const items = data.items || [];
const task = data.task || {};

return items.map(item => ({ json: { ...item, task_info: task } }));

