// Собираем CSV
const data = $json;
const allItems = data.all_items || [];

const headers = ['id', 'section', 'category', 'image', 'file', 'title', 'description'];
let csv = headers.join(',') + '\n';

allItems.forEach((item, index) => {
  const row = {
    id: item.id || `item_${index + 1}`,
    section: item.section || '',
    category: item.category || '',
    image: item.image || '',
    file: item.file || '',
    title: (item.title || '').replace(/"/g, '""').replace(/\n/g, ' '),
    description: (item.description || '').replace(/"/g, '""').replace(/\n/g, ' ')
  };

  const values = headers.map(h => {
    const val = String(row[h] || '');
    if (val.includes(',') || val.includes('\n') || val.includes('"')) return `"${val}"`;
    return val;
  });
  csv += values.join(',') + '\n';
});

const timestamp = Date.now();

return [{
  json: {
    csv_content: csv,
    total_items: allItems.length,
    items: allItems,
    timestamp: timestamp,
    filename: `minecraft_content_${timestamp}`
  },
  binary: $binary
}];

// Создаём массив для максимум 60 попыток (5 минут при wait 5 сек)
return Array(1).fill({
  task_id: $input.first().json.task_id,
  attempt: 0
}).map((item, index) => ({
  json: {
    ...item,
    attempt: index + 1
  }
}));

const base64Items = $('Extract from File').all();
const explodeItems = $('Explode Items1').all();

const results = [];

for (let i = 0; i < base64Items.length; i++) {
  const originalItem = explodeItems[i]?.json || {};
  const base64Data = base64Items[i]?.json?.data || '';
  const binary = base64Items[i]?.binary;

  results.push({
    json: {
      ...originalItem,
      image_base64: base64Data
    },
    binary: binary
  });
}

return results;

const data = $json;
const csvContent = data.csv_content || '';
const filename = data.filename || 'content';

// Конвертируем CSV текст в base64
const base64Csv = Buffer.from(csvContent, 'utf-8').toString('base64');

return {
  json: {
    filename: filename,
    total_items: data.total_items
  },
  binary: {
    data: {
      data: base64Csv,
      mimeType: 'text/csv',
      fileName: filename + '.csv'
    }
  }
};

const allItems = $input.all();

// Собираем все binary в один объект
const allBinaries = {};
const jsonItems = [];

allItems.forEach((item, index) => {
  const json = item.json;
  jsonItems.push(json);

  // Добавляем изображение
  if (item.binary?.image) {
    allBinaries[`img_${index}_${json.image_filename || index + '.png'}`] = item.binary.image;
  }
  if (item.binary?.data) {
    allBinaries[`img_${index}_${json.image_filename || index + '.png'}`] = item.binary.data;
  }

  // Добавляем мод файл
  if (item.binary?.mod_file) {
    allBinaries[`mod_${index}_${json.mod_filename || index + '.mcaddon'}`] = item.binary.mod_file;
  }
});

return [{
  json: {
    total_items: jsonItems.length,
    items: jsonItems
  },
  binary: allBinaries
}];

const data = $json;
const items = data.items || [];
const archiveBinary = $binary?.archive;

const headers = ['id', 'section', 'category', 'image', 'file', 'title', 'description'];
let csv = headers.join(',') + '\n';

items.forEach((item, index) => {
  const row = [
    item.id || `item_${index}`,
    item.section || '',
    item.category || 'general',
    item.image_filename || '',
    item.mod_filename || '',
    `"${(item.title || item.raw_title || '').replace(/"/g, '""')}"`,
    `"${(item.description || item.raw_description || '').replace(/"/g, '""').substring(0, 500)}"`
  ];
  csv += row.join(',') + '\n';
});

// Конвертируем CSV в base64
const csvBase64 = Buffer.from(csv, 'utf-8').toString('base64');

return [{
  json: {
    total_items: items.length,
    filename: `minecraft_content_${Date.now()}`
  },
  binary: {
    archive: archiveBinary,
    csv: {
      data: csvBase64,
      mimeType: 'text/csv',
      fileName: 'content.csv'
    }
  }
}];

const cfg = $json;

const DEFAULT_CATEGORIES = {
  mods: ['Оружие', 'Мебель', 'Транспорт', 'Мобы', 'Броня', 'Инструменты', 'Еда', 'Магия', 'Блоки', 'Руды'],
  maps: ['Приключения', 'Выживание', 'Паркур', 'Хоррор', 'Город', 'Средневековье', 'Мини-игры', 'PvP', 'Редстоун', 'Дома'],
  skins: ['Аниме', 'Супергерои', 'Фильмы', 'Игры', 'Животные', 'Фэнтези', 'Милые', 'Страшные', 'Спорт', 'Военные'],
  textures: ['Реалистичные', 'Мультяшные', 'Средневековье', 'Современные', 'Faithful', 'Простые', 'HD', 'Лёгкие', 'Фэнтези', 'Sci-Fi'],
  shaders: ['Реалистичные', 'Мультяшные', 'Яркие', 'Тёмные', 'Мягкие', 'HDR', 'Кинематограф', 'Лёгкие', 'Ультра', 'Минимал'],
  seeds: ['Деревни', 'Храмы', 'Спавн', 'Биомы', 'Пещеры', 'Горы', 'Острова', 'Редкие', 'Красивые', 'Ресурсы']
};

const SOURCES = {
  mods: { url: 'https://mcpehub.org/mods/', pages: 6 },
  maps: { url: 'https://mcpehub.org/maps/', pages: 6 },
  skins: { url: 'https://mcpehub.org/skins/', pages: 6 },
  textures: { url: 'https://mcpehub.org/textures/', pages: 6 },
  shaders: { url: 'https://mcpehub.org/shaders/', pages: 6 },
  seeds: { url: 'https://mcpehub.org/seeds/', pages: 6 }
};

const projectConfig = {
  chat_id: cfg.chat_id,
  game: cfg.game || 'Minecraft',
  template: cfg.template || 'Crafty',
  target_count: cfg.target_count || 50,
  base_output_dir: cfg.base_output_dir || '/data/content',

  sections: [
    { key: 'mods', name: 'Mods', min_items: 50, min_categories: 5, needs_file: true, file_formats: ['.mcaddon', '.mcpack'], image_size: '640x480', categories: DEFAULT_CATEGORIES.mods, source: SOURCES.mods },
    { key: 'maps', name: 'Maps', min_items: 50, min_categories: 5, needs_file: true, file_formats: ['.mcworld'], image_size: '640x480', categories: DEFAULT_CATEGORIES.maps, source: SOURCES.maps },
    { key: 'skins', name: 'Skins', min_items: 50, min_categories: 5, needs_file: true, file_formats: ['.png'], image_size: '360x640', categories: DEFAULT_CATEGORIES.skins, source: SOURCES.skins },
    { key: 'textures', name: 'Textures', min_items: 50, min_categories: 5, needs_file: false, file_formats: [], image_size: '640x480', categories: DEFAULT_CATEGORIES.textures, source: SOURCES.textures },
    { key: 'shaders', name: 'Shaders', min_items: 50, min_categories: 5, needs_file: false, file_formats: [], image_size: '640x480', categories: DEFAULT_CATEGORIES.shaders, source: SOURCES.shaders },
    { key: 'seeds', name: 'Seeds', min_items: 50, min_categories: 5, needs_file: false, file_formats: [], image_size: '640x480', categories: DEFAULT_CATEGORIES.seeds, source: SOURCES.seeds }
  ],

  text_rules: { language: 'en', title_min: 4, title_max: 30, description_min: 50, description_max: 3000, ban_brands: true }
};

return [{ json: projectConfig }];

const project = $json;
const tasks = [];

for (const section of project.sections || []) {
  tasks.push({
    section_key: section.key,
    section_name: section.name,
    target_items: section.min_items || 50,
    min_categories: section.min_categories || 5,
    available_categories: section.categories || [],
    needs_file: section.needs_file || false,
    file_formats: section.file_formats || [],
    image_size: section.image_size || '640x480',
    source: section.source,
    chat_id: project.chat_id
  });
}

return tasks.map(t => ({ json: t }));

const task = $json;
const source = task.source;
const pagesNeeded = Math.min(Math.ceil(task.target_items / 10) + 1, source.pages || 6);

const pages = [];
for (let i = 1; i <= pagesNeeded; i++) {
  pages.push({
    page_num: i,
    url: i === 1 ? source.url : `${source.url}page/${i}/`,
    task: task
  });
}

return pages.map(p => ({ json: p }));

const response = $json;
const pageInfo = $('Prepare Pages').item;
const task = pageInfo.json.task;
const pageNum = pageInfo.json.page_num;

let html = '';
if (typeof response === 'string') html = response;
else if (response.data) html = response.data;

if (!html || html.length < 500) {
  return [{ json: { page_num: pageNum, items: [], count: 0, task: task } }];
}

const items = [];
const articleRegex = /<article[^>]*>[\s\S]*?<\/article>/gi;
const articles = html.match(articleRegex) || [];

for (const article of articles) {
  const urlMatch = article.match(/<a[^>]*class="[^"]*news-item[^"]*"[^>]*href="([^"]+)"/);
  if (!urlMatch) continue;

  let pageUrl = urlMatch[1];
  if (!pageUrl.includes('.html')) continue;
  if (pageUrl.startsWith('/')) pageUrl = 'https://mcpehub.org' + pageUrl;

  const titleMatch = article.match(/<h2[^>]*>([^<]+)<\/h2>/);
  const title = titleMatch ? titleMatch[1].trim() : '';

  const imgMatch = article.match(/<img[^>]*src="([^"]+)"/);
  let imageUrl = '';
  if (imgMatch) {
    imageUrl = imgMatch[1];
    if (imageUrl.startsWith('/')) imageUrl = 'https://mcpehub.org' + imageUrl;
  }

  const descMatch = article.match(/<p[^>]*class="[^"]*black[^"]*regular[^"]*"[^>]*>([^<]+)<\/p>/);
  const description = descMatch ? descMatch[1].trim() : '';

  if (pageUrl && title && imageUrl) {
    items.push({ title, page_url: pageUrl, image_url: imageUrl, description, source: 'mcpehub.org' });
  }
}

return [{ json: { page_num: pageNum, items: items, count: items.length, task: task } }];

const data = $json;
const pagesData = data.pages_data || [];

let allItems = [];
let task = null;

for (const page of pagesData) {
  if (page.task) task = page.task;
  if (page.items) allItems = allItems.concat(page.items);
}

if (!task) throw new Error('Task not found');

// Убираем дубликаты
const uniqueItems = [];
const seenUrls = new Set();
for (const item of allItems) {
  if (!seenUrls.has(item.page_url)) {
    seenUrls.add(item.page_url);
    uniqueItems.push(item);
  }
}

const targetItems = Math.min(task.target_items || 50, uniqueItems.length);
const limitedItems = uniqueItems.slice(0, targetItems);

const categories = task.available_categories || ['General'];
const minCats = Math.min(task.min_categories || 5, categories.length);

const formattedItems = limitedItems.map((item, i) => ({
  id: `${task.section_key}_${Date.now()}_${i}`,
  section: task.section_key,
  section_name: task.section_name,
  category: categories[i % minCats],
  raw_title: item.title,
  page_url: item.page_url,
  image_url: item.image_url,
  raw_description: item.description,
  needs_file: task.needs_file,
  file_formats: task.file_formats,
  source: item.source
}));

return [{ json: { task, items: formattedItems, total_count: formattedItems.length } }];

const data = $json;
const items = data.items || [];
return items.map(item => ({ json: item }));

const items = $input.all();
const explodeItems = $('Explode Items').all();
const validItems = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const originalJson = explodeItems[i]?.json || {};
  const hasBinary = item.binary && Object.keys(item.binary).length > 0;

  if (hasBinary && !item.json?.error) {
    validItems.push({ json: originalJson, binary: item.binary });
  }
}

if (validItems.length === 0) {
  return [{ json: { skipped: true, reason: 'No valid images' } }];
}

return validItems;

const base64Items = $input.all();
const filterItems = $('Filter Valid').all();
const results = [];

for (let i = 0; i < base64Items.length; i++) {
  const filterItem = filterItems[i];
  if (!filterItem || filterItem.json?.skipped) continue;

  results.push({
    json: { ...filterItem.json, image_base64: base64Items[i]?.json?.data || '' },
    binary: base64Items[i]?.binary
  });
}

if (results.length === 0) return [{ json: { skipped: true } }];
return results;

