parameters.jsCode:
const genItems = $('Generate URLs1').all();
const idx = $itemIndex;
const meta = genItems[idx]?.json || {};

const section = meta._section || 'unknown';
const categories = meta._categories || ['General'];
const selectors = meta._selectors || {};
const baseUrl = meta._base_url || 'https://mcpehub.org';
const fields = meta._fields || { title: true, description: true, image: true };

const input = $input.item.json;
let html = '';
if (typeof input === 'string') html = input;
else if (input?.data) html = input.data;
else if (input?.body) html = input.body;

if (!html || html.length < 500) {
  return { json: { section, items: [], count: 0, _chat_id: meta._chat_id, _items_limit: meta._items_limit, _fields: fields } };
}

const results = [];

// Используем селекторы из конфига
const articleRegex = new RegExp(selectors.article || '<article[^>]*>[\\s\\S]*?</article>', 'gi');
const articles = html.match(articleRegex) || [];

for (const article of articles) {
  // URL
  const urlRegex = new RegExp(selectors.url || '<a[^>]*href="([^"]+\\.html)"');
  const urlMatch = article.match(urlRegex);
  if (!urlMatch) continue;
  let pageUrl = urlMatch[1];
  if (pageUrl.startsWith('/')) pageUrl = baseUrl + pageUrl;

  // Title
  let title = '';
  if (fields.title) {
    const titleRegex = new RegExp(selectors.title || '<h2[^>]*>([^<]+)</h2>');
    const titleMatch = article.match(titleRegex);
    title = titleMatch ? titleMatch[1].trim() : '';
  }

  // Image
  let imageUrl = '';
  if (fields.image) {
    const imgRegex = new RegExp(selectors.image || '<img[^>]*src="([^"]+)"');
    const imgMatch = article.match(imgRegex);
    imageUrl = imgMatch ? imgMatch[1] : '';
    if (imageUrl.startsWith('/')) imageUrl = baseUrl + imageUrl;
  }

  // Description
  let description = '';
  if (fields.description) {
    const descRegex = new RegExp(selectors.description || '<p[^>]*>([^<]+)</p>');
    const descMatch = article.match(descRegex);
    description = descMatch ? descMatch[1].trim() : '';
  }

  if (title && pageUrl) {
    results.push({
      section,
      category: categories[results.length % categories.length],
      title,
      page_url: pageUrl,
      image_url: imageUrl,
      description
    });
  }
}

return { json: { section, items: results, count: results.length, _chat_id: meta._chat_id, _items_limit: meta._items_limit, _fields: fields } };

// Для ветки БЕЗ картинок - сразу финализируем
const items = $input.all();

return items.map(item => ({
  json: {
    id: item.json.id,
    section: item.json.section,
    category: item.json.category,
    image: '',
    file: '',
    title: (item.json.title || '').substring(0, 50),
    description: (item.json.description || '').substring(0, 500),
    qa_score: 0,
    _chat_id: item.json._chat_id
  }
}));

const data = $json;
const items = data.final_items || [];
let chatId = 0;

const stats = {};
for (const item of items) {
  stats[item.section] = (stats[item.section] || 0) + 1;
  if (item._chat_id) chatId = item._chat_id;
}

const headers = ['id', 'section', 'category', 'image', 'file', 'title', 'description'];
let csv = headers.join(',') + '\n';

items.forEach(item => {
  const title = (item.title || '').replace(/"/g, '').replace(/\n/g, ' ');
  const desc = (item.description || '').replace(/"/g, '').replace(/\n/g, ' ');
  csv += [item.id, item.section, item.category, item.image, '', `"${title}"`, `"${desc}"`].join(',') + '\n';
});

const csvB64 = Buffer.from(csv, 'utf-8').toString('base64');
const filename = `content_${Date.now()}`;

const finalizeItems = $('Finalize2').all();
const binaryKeys = ['content.csv'];
const binaryData = { 'content.csv': { data: csvB64, mimeType: 'text/csv', fileName: 'content.csv' } };

for (const item of finalizeItems) {
  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      binaryData[key] = item.binary[key];
      binaryKeys.push(key);
    }
  }
}

return {
  json: { total_items: items.length, filename, stats, chat_id: chatId, binary_keys: binaryKeys.join(',') },
  binary: binaryData
};

const data = $('Parse AI Config').first().json;
const config = data.config || {};
const sourceConfig = data.source_config || {};
const sections = config.sections || ['mods'];
const pagesPerSection = data.pages_per_section || 6;
const categories = data.categories || {};
const itemsPerSection = config.items_per_section || 50;
const chatId = data.chat_id;

const pages = [];
for (const section of sections) {
  for (let p = 1; p <= Math.min(pagesPerSection, 6); p++) {
    const url = p === 1 
      ? `${sourceConfig.base_url}/${section}/`
      : `${sourceConfig.base_url}/${section}${sourceConfig.page_pattern.replace('{page}', p)}`;

    pages.push({
      _section: section,
      _page: p,
      _categories: (categories[section] || ['General']).slice(0, config.categories_count || 5),
      _selectors: sourceConfig.selectors,
      _base_url: sourceConfig.base_url,
      _items_limit: itemsPerSection,
      _chat_id: chatId,
      _fields: config.fields,
      url: url
    });
  }
}

return pages.map(p => ({ json: p }));

const data = $json;
const pages = data.all_pages || [];

let chatId = 0, itemsLimit = 50, fields = {};
let allItems = [];

for (const page of pages) {
  if (page._chat_id) chatId = page._chat_id;
  if (page._items_limit) itemsLimit = page._items_limit;
  if (page._fields) fields = page._fields;
  if (page.items) allItems = allItems.concat(page.items);
}

// Дедупликация
const unique = [];
const seen = new Set();
for (const item of allItems) {
  if (item.page_url && !seen.has(item.page_url)) {
    seen.add(item.page_url);
    unique.push(item);
  }
}

// Группировка с лимитом
const bySection = {};
for (const item of unique) {
  if (!bySection[item.section]) bySection[item.section] = [];
  if (bySection[item.section].length < itemsLimit) {
    bySection[item.section].push(item);
  }
}

// Формируем items
const items = [];
let idx = 0;
for (const section of Object.keys(bySection)) {
  for (const item of bySection[section]) {
    const safeTitle = item.title.toLowerCase().replace(/[^a-z0-9]/gi, '_').substring(0, 15);
    items.push({
      json: {
        id: `${section}_${idx}`,
        section: item.section,
        category: item.category,
        title: item.title.replace(/^(Мод|Карта|Скин|Текстура|Шейдер|Сид):\s*/i, '').trim(),
        image_url: item.image_url,
        image_filename: `${section}_${safeTitle}_${idx}.jpg`,
        description: item.description || `${item.title} - content`,
        _chat_id: chatId,
        _need_image: fields.image !== false
      }
    });
    idx++;
  }
}

return items;

// Для ветки с картинками
const needImgItems = $('Need Images?').all().filter(i => i.json._need_image);
const idx = $itemIndex;
const meta = needImgItems[idx]?.json || {};

const current = $input.item;
const hasBinary = current.binary && Object.keys(current.binary).length > 0;
const hasError = current.json?.error || current.json?.statusCode >= 400;

if (!hasBinary || hasError) {
  return { json: { _skip: true, id: meta.id } };
}

return {
  json: { ...meta },
  binary: current.binary
};

const validItems = $('Filter Valid2').all().filter(i => !i.json._skip);
const idx = $itemIndex;
const meta = validItems[idx]?.json || {};
const binary = validItems[idx]?.binary;
const b64 = $input.item.json?.data || '';

return {
  json: { ...meta, image_base64: b64 },
  binary: binary
};

